### Change 5: Create the test file

**File to create:** `tests/pipelines/test_pipelines_image_text_to_text.js`

The test runner at `tests/test_utils.js` line 124 uses `fs.readdirSync(pipelines_dir)` and auto-imports every file it finds — so dropping a file in `tests/pipelines/` is the only registration step needed.

```javascript
import { pipeline, ImageTextToTextPipeline, RawImage } from "../../src/transformers.js";

import { MAX_MODEL_LOAD_TIME, MAX_TEST_EXECUTION_TIME, MAX_MODEL_DISPOSE_TIME, DEFAULT_MODEL_OPTIONS } from "../init.js";

const PIPELINE_ID = "image-text-to-text";

export default () => {
  describe("Image Text To Text", () => {
    const model_id = "Xenova/tiny-random-LlavaForConditionalGeneration";

    /** @type {ImageTextToTextPipeline} */
    let pipe;
    let image;

    beforeAll(async () => {
      pipe = await pipeline(PIPELINE_ID, model_id, DEFAULT_MODEL_OPTIONS);
      // Construct a 224x224 white image — same dimensions used in the LLava model test
      const dims = [224, 224, 3];
      image = new RawImage(new Uint8ClampedArray(dims[0] * dims[1] * dims[2]).fill(255), ...dims);
    }, MAX_MODEL_LOAD_TIME);

    it("should be an instance of ImageTextToTextPipeline", () => {
      expect(pipe).toBeInstanceOf(ImageTextToTextPipeline);
    });

    describe("batch_size=1", () => {
      it(
        "default",
        async () => {
          // LLava requires the special <image> token in the prompt
          const prompt = "USER: <image>\nWhat's the content of the image? ASSISTANT:";
          const output = await pipe(image, prompt, { max_new_tokens: 10 });
          // Output is a flat array of result objects for single input
          expect(Array.isArray(output)).toBe(true);
          expect(output.length).toBeGreaterThan(0);
          expect(typeof output[0].generated_text).toBe("string");
        },
        MAX_TEST_EXECUTION_TIME,
      );
    });

    describe("batch_size>1", () => {
      it(
        "default",
        async () => {
          const prompts = [
            "USER: <image>\nWhat's the content of the image? ASSISTANT:",
            "<image>Hi",
          ];
          const output = await pipe([image, image], prompts, { max_new_tokens: 10 });
          // Output is an array of arrays for batched input
          expect(Array.isArray(output)).toBe(true);
          expect(output.length).toBe(2);
          expect(Array.isArray(output[0])).toBe(true);
          expect(typeof output[0][0].generated_text).toBe("string");
        },
        MAX_TEST_EXECUTION_TIME,
      );
    });

    afterAll(async () => {
      await pipe.dispose();
    }, MAX_MODEL_DISPOSE_TIME);
  });
};
```

**Notes on test design:**
- `Xenova/tiny-random-LlavaForConditionalGeneration` is confirmed to exist in the test suite already (`tests/models/llava/test_modeling_llava.js` line 17) with ONNX weights available.
- The `RawImage` constructor approach (filling a `Uint8ClampedArray`) avoids network fetches, matching the LLava model test pattern.
- Output shape assertions use `typeof` and `Array.isArray` rather than exact string matching, because tiny random models produce non-deterministic garbage text — consistent with how the `DocumentQuestionAnsweringPipeline` test uses `[{ answer: null }]` as the exact output of a tiny model.
- `max_new_tokens: 10` bounds runtime for CI.

