### Step 2 — Add JSDoc typedefs and pipeline class in `src/pipelines.js`

**Location:** immediately after the closing `}` of `ImageToTextPipeline` (currently line
2005), before the `ImageClassificationSingle` typedef comment that begins at line 2007.

```js
/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Generate text conditioned on an image and a text prompt.
 * @param {ImageInput|ImageInput[]} images The image(s) to process.
 * @param {string|string[]} texts The text prompt(s) to condition generation on.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using `AutoModelForImageTextToText`. This pipeline generates
 * text from an image and an optional text prompt, and is suitable for decoder-only
 * vision-language models such as LLaVA, SmolVLM, PaliGemma, and Florence-2.
 *
 * **Example:** Generate a response from an image and a text prompt w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(image, 'Describe this image.');
 * // [{ generated_text: 'Two cats are lying on a couch.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, texts, generate_kwargs = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        if (!Array.isArray(texts)) {
            texts = new Array(preparedImages.length).fill(texts);
        }

        const toReturn = [];
        for (let i = 0; i < preparedImages.length; ++i) {
            // Processor combines image preprocessing and text tokenization in one call
            const inputs = await this.processor(preparedImages[i], texts[i]);

            // Decoder-only models return the full sequence (prompt + generated tokens).
            // Slice off the prompt portion to return only the newly generated text.
            const output = await this.model.generate({ ...inputs, ...generate_kwargs });
            const input_length = inputs.input_ids.dims[1];
            const decoded = this.tokenizer.batch_decode(
                /** @type {Tensor} */ (output).slice(null, [input_length, null]),
                { skip_special_tokens: true },
            ).map(x => ({ generated_text: x.trim() }));
            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

**Design notes:**
- Processes each image-text pair separately (one iteration per pair), mirroring
  `ImageToTextPipeline`'s per-batch loop. This avoids padding complexity and works
  correctly with processors that expand `<image>` tokens in the prompt.
- `output.slice(null, [input_length, null])` strips prompt tokens from the decoder-only
  output — the same pattern used in `tests/models/llava/test_modeling_llava.js` line 45.
- Return shape: single input → `[{generated_text}]`; batched → `[[{...}], [{...}]]`.
  This exactly mirrors `ImageToTextPipeline`'s `isBatched ? toReturn : toReturn[0]`.
- Reuses existing helpers: `prepareImages` (line 91), `TextImagePipelineConstructorArgs`
  (line 215), `Tensor` (already imported line 71).

