import { pipeline, ImageTextToTextPipeline, RawImage } from "../../src/transformers.js";

import { MAX_MODEL_LOAD_TIME, MAX_TEST_EXECUTION_TIME, MAX_MODEL_DISPOSE_TIME, DEFAULT_MODEL_OPTIONS } from "../init.js";

const PIPELINE_ID = "image-text-to-text";

export default () => {
  describe("Image Text To Text", () => {
    const model_id = "Xenova/tiny-random-LlavaForConditionalGeneration";

    /** @type {ImageTextToTextPipeline} */
    let pipe;
    let image;

    beforeAll(async () => {
      pipe = await pipeline(PIPELINE_ID, model_id, DEFAULT_MODEL_OPTIONS);
      // 224×224 white image — same dimensions used in tests/models/llava/test_modeling_llava.js
      const dims = [224, 224, 3];
      image = new RawImage(new Uint8ClampedArray(dims[0] * dims[1] * dims[2]).fill(255), ...dims);
    }, MAX_MODEL_LOAD_TIME);

    it("should be an instance of ImageTextToTextPipeline", () => {
      expect(pipe).toBeInstanceOf(ImageTextToTextPipeline);
    });

    describe("batch_size=1", () => {
      it(
        "default",
        async () => {
          // LLaVA requires the special <image> token in the prompt
          const prompt = "USER: <image>\nWhat's the content of the image? ASSISTANT:";
          const output = await pipe(image, prompt, { max_new_tokens: 10 });
          expect(Array.isArray(output)).toBe(true);
          expect(output.length).toBeGreaterThan(0);
          expect(typeof output[0].generated_text).toBe("string");
        },
        MAX_TEST_EXECUTION_TIME,
      );
    });

    describe("batch_size>1", () => {
      it(
        "default",
        async () => {
          const prompts = [
            "USER: <image>\nWhat's the content of the image? ASSISTANT:",
            "<image>Hi",
          ];
          const output = await pipe([image, image], prompts, { max_new_tokens: 10 });
          expect(Array.isArray(output)).toBe(true);
          expect(output.length).toBe(2);
          expect(Array.isArray(output[0])).toBe(true);
          expect(typeof output[0][0].generated_text).toBe("string");
        },
        MAX_TEST_EXECUTION_TIME,
      );
    });

    afterAll(async () => {
      await pipe.dispose();
    }, MAX_MODEL_DISPOSE_TIME);
  });
};
```

**Test model rationale:** `Xenova/tiny-random-LlavaForConditionalGeneration` is already
confirmed to work in `tests/models/llava/test_modeling_llava.js`. Assertions are structural
(`typeof`, `Array.isArray`) rather than exact-value, since tiny random models produce
non-deterministic output.

