/**
 * Image-text-to-text pipeline using `AutoModelForImageTextToText`. This pipeline generates text
 * conditioned on an image and a text prompt, supporting multimodal language models such as
 * LLaVA, SmolVLM, PaliGemma, and Florence-2.
 *
 * **Example:** Generate a response from an image and a text prompt w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const messages = [{ role: 'user', content: [{ type: 'image' }, { type: 'text', text: 'Describe the image.' }] }];
 * const output = await pipe(url, messages, { max_new_tokens: 128 });
 * // [{ generated_text: '...' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, texts, generate_kwargs = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        if (!Array.isArray(texts)) {
            texts = new Array(preparedImages.length).fill(texts);
        }

        const toReturn = [];
        for (let i = 0; i < preparedImages.length; ++i) {
            const image = preparedImages[i];
            const text = texts[i];
            const inputs = await this.processor(image, text);
            const outputIds = await this.model.generate({ ...inputs, ...generate_kwargs });
            // Slice off the prompt tokens so only the newly generated tokens are decoded
            const newIds = /** @type {import('./utils/tensor.js').Tensor} */ (outputIds).slice(null, [inputs.input_ids.dims[1], null]);
            const decoded = this.tokenizer.batch_decode(newIds, {
                skip_special_tokens: true,
            }).map(x => ({ generated_text: x.trim() }));
            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}

